import { Type } from './Type.js';
/**
 * Type that maps an SQL DECIMAL to a JS string or number.
 */
export class DecimalType extends Type {
    mode;
    constructor(mode) {
        super();
        this.mode = mode;
    }
    /* v8 ignore next */
    convertToJSValue(value) {
        if ((this.mode ?? this.prop?.runtimeType) === 'number') {
            return +value;
        }
        return String(value);
    }
    compareValues(a, b) {
        return this.platform.formatDecimal(a, this.prop?.scale) === this.platform.formatDecimal(b, this.prop?.scale);
    }
    getColumnType(prop, platform) {
        return platform.getDecimalTypeDeclarationSQL(prop);
    }
    compareAsType() {
        return this.mode ?? this.prop?.runtimeType ?? 'string';
    }
}
